// // This module implements a 1-bit wide 2-to-1 demultiplexer. When the select signal S is low (0), the output Y will be equal to input B; when S is high (1), the output Y will switch to input A.
module top_module(
    // Input ports
    input A,
    input B,
    input S,

    // Output port
    output Y
);assign Y = (S == 1) ? B : A;

endmodule
